import pytest
import requests

BASE_URL = "http://fhir-lite:8080"

@pytest.mark.parametrize("date,score,expected_status", [
    ("2024-01-01T00:00:00Z", 1,  201),
    ("9999-12-31T23:59:59Z", 10, 201),
    ("2024-06-01T08:00:00Z", 0,  422),
    ("2024-06-01T08:00:00Z", 11, 422),
])
def test_referral_with_boundary_timestamp_and_priority_score(
    clinician_auth_token, patient_with_consent, target_facility_id,
    date, score, expected_status
):
    payload = {
        "patientId": patient_with_consent,
        "targetFacilityId": target_facility_id,
        "priority": "routine",
        "requestedDate": date,
        "priority_score": score
    }
    headers = {"Authorization": f"Bearer {clinician_auth_token}",
               "Content-Type": "application/json"}

    resp = requests.post(f"{BASE_URL}/ReferralRequest", json=payload, headers=headers)

    assert resp.status_code == expected_status, (
        f"score={score} date={date}: expected {expected_status}, got {resp.status_code}: {resp.text}"
    )
    if expected_status == 422:
        assert "priority_score" in resp.json().get("fields", {})
